import express from 'express';

export function createApp() {
  const app = express();
  app.use(express.json());
  app.get('/health', (_req, res) => res.json({ ok: true }));
  app.get('/api/message', (_req, res) => res.json({ message: 'Hello from Express' }));
  return app;
}

if (process.argv[1]?.endsWith('server.js')) {
  createApp().listen(3000, () => console.log('API listening on :3000'));
}

import assert from 'node:assert/strict';
import { createApp } from '../src/server.js';

const routes = createApp()._router.stack.filter((layer) => layer.route).map((layer) => layer.route.path);
assert(routes.includes('/health'));
console.log('express smoke ok');
